// // This module implements a 3-bit down/up counter using behavioral Verilog. The counter decrements when the up_down signal is high and increments when the up_down signal is low.
module up_down_counter_3bit (
    input clk,
    input reset,
    input up_down,
    output reg [2:0] count
);

always @(posedge clk) begin
    if (reset) begin
        count <= 3'b000;
    end else begin
        if (up_down) begin
            count <= count + 1;
        end else begin
            count <= count - 1;
        end
    end
end

endmodule
